FILES = {'src/frontend/command_center/modern/claire_portal_responsive_layout.css': '/*\n  Claire v17.62 — Portal Resize + Readability Stabilization\n\n  This stylesheet intentionally avoids changing runtime logic. It makes the\n  operating environment readable by allowing portal content to wrap, scroll,\n  resize, and breathe across different monitor sizes.\n*/\n\n:root {\n  --claire-shell-gap: clamp(12px, 1.5vw, 22px);\n  --claire-panel-radius: 18px;\n  --claire-readable-line: 1.55;\n  --claire-min-panel-width: 280px;\n  --claire-max-content-width: 1720px;\n  --claire-dashboard-search-height: 58px;\n}\n\nhtml,\nbody {\n  min-width: 0 !important;\n  overflow-x: hidden !important;\n}\n\nbody {\n  overflow-wrap: anywhere;\n}\n\n/* General readability repair */\nmain,\nsection,\narticle,\naside,\ndiv,\nnav,\nheader,\nfooter {\n  min-width: 0;\n}\n\np,\nli,\nspan,\ntd,\nth,\nbutton,\nlabel,\ninput,\ntextarea,\nselect,\npre,\ncode,\n.claire-card,\n.stage-card,\n.loop-card,\n.source-card,\n.route-col,\n.validation-node,\n.roadmap-card {\n  max-width: 100%;\n  overflow-wrap: anywhere;\n  word-break: normal;\n}\n\np,\nli,\n.claire-card,\n.stage-card,\n.loop-card,\n.source-card,\n.route-col,\n.validation-node,\n.roadmap-card {\n  line-height: var(--claire-readable-line);\n}\n\n/* Give the redesigned dashboard room to breathe. */\nmain,\n#app,\n#workspace,\n#main-workspace,\n.command-center,\n.operating-environment,\n.claire-operating-environment,\n.claire-shell,\n.dashboard-shell {\n  width: min(100%, var(--claire-max-content-width));\n  max-width: var(--claire-max-content-width);\n  margin-left: auto;\n  margin-right: auto;\n}\n\n/* Prevent old panels from collapsing content into unreadable columns. */\n.grid,\n.portal-grid,\n.surface-grid,\n.dashboard-grid,\n.lifecycle-grid,\n.route-grid,\n.cards-grid,\n.panel-grid {\n  min-width: 0;\n}\n\n.portal-grid,\n.surface-grid,\n.dashboard-grid,\n.route-grid,\n.lifecycle-grid,\n.cards-grid,\n.panel-grid,\n.grid[data-claire-grid],\n[class*="grid"] {\n  gap: var(--claire-shell-gap);\n}\n\n/* Clamp tight auto-fit grids into readable sizes. */\n.portal-grid,\n.surface-grid,\n.dashboard-grid,\n.cards-grid,\n.panel-grid {\n  grid-template-columns: repeat(auto-fit, minmax(var(--claire-min-panel-width), 1fr)) !important;\n}\n\n.lifecycle-grid,\n.stage-grid,\n#lifecycle-grid,\n#stage-grid {\n  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)) !important;\n}\n\n/* Portal surfaces should be viewable, scrollable, and manually resizable. */\n.portal,\n.claire-portal,\n.surface,\n.claire-surface,\n.dashboard-panel,\n.claire-panel,\n.stage-card,\n.loop-card,\n.source-card,\n.route-col,\n.validation-node,\n.roadmap-card,\n.claire-validation-authority-panel,\n.claire-memory-panel {\n  min-height: 120px;\n  max-height: min(72vh, 760px);\n  overflow: auto;\n  resize: vertical;\n  scrollbar-width: thin;\n  border-radius: var(--claire-panel-radius);\n}\n\n/* Some panels need to show more by default. */\n.claire-validation-authority-panel,\n.claire-memory-panel,\n#claire-validation-authority-panel,\n#claire-verified-memory-panel,\n#route-gate,\n#route,\n#routes,\n#autodesign,\n#design,\n#validation,\n#evidence,\n#memory,\n#runtime,\n#update-packs {\n  min-height: 220px;\n}\n\n/* Long JSON-like or evidence text should not break the layout. */\npre,\ncode,\n.json-viewer,\n.raw-json,\n.evidence-item,\n.trace-item,\n.output-preview,\n.runtime-truth,\n.validation-report,\n.memory-report {\n  white-space: pre-wrap !important;\n  overflow-wrap: anywhere !important;\n  max-width: 100%;\n  overflow-x: auto;\n}\n\n/* Tables should scroll instead of forcing the page wider. */\ntable {\n  width: 100%;\n  max-width: 100%;\n}\n\n.table-wrap,\n.status-table-wrap,\n.overflow-x-auto {\n  overflow-x: auto;\n  max-width: 100%;\n}\n\n/* Side rails and proof bars need wrapping. */\n.right-rail,\n.live-rail,\n.narrative-rail,\n.proofbar,\n.status-rail,\n.bottom-rail,\n.claire-proofbar {\n  min-width: 0;\n  overflow-wrap: anywhere;\n}\n\n.proofbar,\n.status-rail,\n.bottom-rail,\n.claire-proofbar {\n  flex-wrap: wrap;\n  row-gap: 8px;\n}\n\n/* Navigation labels should not hide meaning. */\n.nav-sidebar a,\n.side-nav a,\n.sidebar a,\n[role="navigation"] a {\n  white-space: normal !important;\n  overflow: visible !important;\n  text-overflow: clip !important;\n  line-height: 1.35;\n}\n\n/* Keep the search command bar from hiding page anchors. */\nbody {\n  scroll-padding-top: calc(var(--claire-dashboard-search-height) + 18px);\n}\n\n.claire-search-mounted main,\n.claire-search-mounted #app,\n.claire-search-mounted #workspace,\n.claire-search-mounted #main-workspace {\n  padding-top: 0;\n}\n\n/* Responsive behavior */\n@media (max-width: 1280px) {\n  :root {\n    --claire-min-panel-width: 260px;\n  }\n\n  main,\n  #app,\n  #workspace,\n  #main-workspace {\n    width: calc(100% - 24px);\n  }\n}\n\n@media (max-width: 900px) {\n  :root {\n    --claire-min-panel-width: 100%;\n    --claire-shell-gap: 12px;\n  }\n\n  .portal,\n  .claire-portal,\n  .surface,\n  .claire-surface,\n  .dashboard-panel,\n  .claire-panel,\n  .stage-card,\n  .loop-card,\n  .source-card,\n  .route-col,\n  .validation-node,\n  .roadmap-card,\n  .claire-validation-authority-panel,\n  .claire-memory-panel {\n    max-height: none;\n    resize: none;\n  }\n\n  .toolbar {\n    position: static !important;\n    margin: 10px;\n    flex-wrap: wrap;\n  }\n}\n\n@media (max-width: 640px) {\n  .claire-dashboard-search-shell {\n    left: 10px !important;\n    right: 10px !important;\n    top: 10px !important;\n  }\n\n  body {\n    padding-top: 74px;\n  }\n}\n', 'src/frontend/command_center/modern/dashboard_search_contract.json': '{\n  "schema": "claire.dashboard_search_contract.v1",\n  "version": "17.62",\n  "purpose": "Define the dashboard-wide search and standalone intelligence command-bar foundation.",\n  "search_scope": [\n    "visible dashboard text",\n    "dashboard_architecture_map.json",\n    "lifecycle_stage_registry.json",\n    "runtime_surface_registry.json",\n    "route_surface_registry.json",\n    "runtime_truth_status.json",\n    "dashboard_runtime_truth.json",\n    "validation_authority_status.json",\n    "evidence_traceability_status.json",\n    "verified_memory_status.json",\n    "recursive_feedback_status.json"\n  ],\n  "rules": [\n    "Search must not fake internet or autonomous intelligence results.",\n    "Search must label missing data honestly.",\n    "Search may summarize local dashboard/runtime truth only.",\n    "Future standalone intelligence can replace the local index through the same contract."\n  ],\n  "future_extension_points": [\n    "standalone Claire intelligence service",\n    "source-governed external search",\n    "runtime command execution",\n    "validated evidence retrieval",\n    "design simulation portal search"\n  ]\n}\n', 'src/frontend/command_center/modern/intelligence_command_contract.json': '{\n  "schema": "claire.intelligence_command_contract.v1",\n  "version": "17.62",\n  "purpose": "Prepare Claire\'s dashboard command/search layer for a future standalone intelligence engine.",\n  "current_mode": "local_dashboard_truth_search",\n  "future_mode": "standalone_claire_intelligence",\n  "current_capabilities": [\n    "search local dashboard text",\n    "search local architecture/runtime/status JSON files when fetchable",\n    "jump to matching visible sections",\n    "show missing runtime truth honestly",\n    "surface validation/memory blockers if present"\n  ],\n  "not_yet_claimed": [\n    "full autonomous internet intelligence",\n    "model-level self-directed reasoning loop",\n    "self-modifying runtime",\n    "unvalidated memory mutation"\n  ],\n  "safety_rule": "Standalone intelligence must preserve validation, evidence, runtime isolation, rollback safety, and memory gates."\n}\n', 'src/frontend/command_center/modern/claire_dashboard_search.js': '(function () {\n  "use strict";\n\n  const LOCAL_JSON_PATHS = [\n    "dashboard_architecture_map.json",\n    "lifecycle_stage_registry.json",\n    "runtime_surface_registry.json",\n    "route_surface_registry.json",\n    "runtime_truth_contract.json",\n    "runtime_truth_status.json",\n    "validation_authority_status.json",\n    "evidence_traceability_status.json",\n    "verified_memory_status.json",\n    "recursive_feedback_status.json",\n    "dashboard_search_contract.json",\n    "intelligence_command_contract.json",\n    "./dashboard_architecture_map.json",\n    "./lifecycle_stage_registry.json",\n    "./runtime_surface_registry.json",\n    "./route_surface_registry.json",\n    "./runtime_truth_contract.json",\n    "./runtime_truth_status.json",\n    "./validation_authority_status.json",\n    "./evidence_traceability_status.json",\n    "./verified_memory_status.json",\n    "./recursive_feedback_status.json",\n    "./dashboard_search_contract.json",\n    "./intelligence_command_contract.json",\n    "../../../exports/latest/dashboard_runtime_truth.json",\n    "../../../exports/latest/validation_authority_report.json",\n    "../../../exports/latest/evidence_traceability_index.json",\n    "../../../exports/latest/verified_memory_gate_report.json",\n    "../../../exports/latest/recursive_feedback_gate_report.json",\n    "exports/latest/dashboard_runtime_truth.json",\n    "exports/latest/validation_authority_report.json",\n    "exports/latest/evidence_traceability_index.json",\n    "exports/latest/verified_memory_gate_report.json",\n    "exports/latest/recursive_feedback_gate_report.json"\n  ];\n\n  const state = {\n    documents: [],\n    selectedIndex: -1,\n    lastQuery: ""\n  };\n\n  function escapeHtml(value) {\n    return String(value ?? "")\n      .replace(/&/g, "&amp;")\n      .replace(/</g, "&lt;")\n      .replace(/>/g, "&gt;")\n      .replace(/"/g, "&quot;");\n  }\n\n  function normalizeText(value) {\n    return String(value ?? "")\n      .replace(/\\s+/g, " ")\n      .trim();\n  }\n\n  function flattenJson(value, prefix = "") {\n    const rows = [];\n\n    function walk(node, path) {\n      if (node === null || node === undefined) return;\n\n      if (Array.isArray(node)) {\n        node.forEach((item, index) => walk(item, `${path}[${index}]`));\n        return;\n      }\n\n      if (typeof node === "object") {\n        Object.entries(node).forEach(([key, item]) => {\n          const next = path ? `${path}.${key}` : key;\n          walk(item, next);\n        });\n        return;\n      }\n\n      rows.push(`${path}: ${String(node)}`);\n    }\n\n    walk(value, prefix);\n    return rows.join("\\n");\n  }\n\n  async function fetchJson(path) {\n    try {\n      const response = await fetch(path, { cache: "no-store" });\n      if (!response.ok) return null;\n      return await response.json();\n    } catch (_) {\n      return null;\n    }\n  }\n\n  function collectVisibleSections() {\n    const selectors = [\n      "section",\n      "article",\n      ".portal",\n      ".claire-portal",\n      ".surface",\n      ".claire-surface",\n      ".dashboard-panel",\n      ".claire-panel",\n      ".stage-card",\n      ".route-col",\n      ".validation-node",\n      ".roadmap-card",\n      "#claire-validation-authority-panel",\n      "#claire-verified-memory-panel"\n    ];\n\n    const nodes = Array.from(document.querySelectorAll(selectors.join(",")));\n    const seen = new Set();\n\n    nodes.forEach((node, index) => {\n      if (!node || seen.has(node)) return;\n      seen.add(node);\n\n      const text = normalizeText(node.innerText || node.textContent || "");\n      if (!text || text.length < 12) return;\n\n      if (!node.id) {\n        node.id = `claire-search-section-${index + 1}`;\n      }\n\n      const titleNode = node.querySelector("h1,h2,h3,.section-title,.claire-validation-title,.claire-memory-title");\n      const title = normalizeText(titleNode?.innerText || titleNode?.textContent || node.getAttribute("aria-label") || node.id || `Section ${index + 1}`);\n\n      state.documents.push({\n        type: "visible_surface",\n        title,\n        path: `#${node.id}`,\n        text,\n        targetId: node.id\n      });\n    });\n  }\n\n  async function collectJsonDocuments() {\n    const uniquePaths = [...new Set(LOCAL_JSON_PATHS)];\n    for (const path of uniquePaths) {\n      const json = await fetchJson(path);\n      if (!json) continue;\n\n      const text = flattenJson(json);\n      if (!text) continue;\n\n      state.documents.push({\n        type: "runtime_or_contract_json",\n        title: path.split("/").pop() || path,\n        path,\n        text,\n        json\n      });\n    }\n  }\n\n  function scoreDocument(doc, queryParts) {\n    const haystack = `${doc.title}\\n${doc.path}\\n${doc.text}`.toLowerCase();\n    let score = 0;\n\n    for (const part of queryParts) {\n      if (!part) continue;\n      if (doc.title.toLowerCase().includes(part)) score += 12;\n      if (doc.path.toLowerCase().includes(part)) score += 6;\n\n      const occurrences = haystack.split(part).length - 1;\n      score += Math.min(occurrences, 12);\n    }\n\n    return score;\n  }\n\n  function snippet(text, queryParts) {\n    const clean = normalizeText(text);\n    const lower = clean.toLowerCase();\n\n    let index = -1;\n    for (const part of queryParts) {\n      index = lower.indexOf(part);\n      if (index >= 0) break;\n    }\n\n    if (index < 0) return clean.slice(0, 220);\n\n    const start = Math.max(0, index - 80);\n    const end = Math.min(clean.length, index + 180);\n    return `${start > 0 ? "…" : ""}${clean.slice(start, end)}${end < clean.length ? "…" : ""}`;\n  }\n\n  function search(query) {\n    const parts = normalizeText(query).toLowerCase().split(" ").filter(Boolean);\n    if (!parts.length) return [];\n\n    return state.documents\n      .map((doc) => ({\n        doc,\n        score: scoreDocument(doc, parts),\n        snippet: snippet(doc.text, parts)\n      }))\n      .filter((item) => item.score > 0)\n      .sort((a, b) => b.score - a.score)\n      .slice(0, 12);\n  }\n\n  function ensureStyles() {\n    if (document.getElementById("claire-dashboard-search-style")) return;\n\n    const style = document.createElement("style");\n    style.id = "claire-dashboard-search-style";\n    style.textContent = `\n      .claire-dashboard-search-shell {\n        position: fixed;\n        top: 14px;\n        left: 50%;\n        transform: translateX(-50%);\n        z-index: 10040;\n        width: min(760px, calc(100vw - 40px));\n        color: #e2e8f0;\n        font-family: Inter, system-ui, sans-serif;\n      }\n\n      .claire-dashboard-search-box {\n        display: flex;\n        align-items: center;\n        gap: 10px;\n        border: 1px solid rgba(0, 212, 255, 0.34);\n        border-radius: 999px;\n        padding: 9px 14px;\n        background: rgba(5, 10, 20, 0.88);\n        backdrop-filter: blur(18px);\n        box-shadow: 0 0 28px rgba(0, 212, 255, 0.12);\n      }\n\n      .claire-dashboard-search-label {\n        font-family: Orbitron, Inter, system-ui, sans-serif;\n        color: #00d4ff;\n        font-size: 10px;\n        font-weight: 800;\n        letter-spacing: .16em;\n        text-transform: uppercase;\n        white-space: nowrap;\n      }\n\n      .claire-dashboard-search-input {\n        flex: 1;\n        min-width: 0;\n        border: 0;\n        outline: 0;\n        background: transparent;\n        color: #f8fafc;\n        font-size: 14px;\n        line-height: 1.4;\n      }\n\n      .claire-dashboard-search-input::placeholder {\n        color: #64748b;\n      }\n\n      .claire-dashboard-search-kbd {\n        border: 1px solid rgba(148, 163, 184, 0.24);\n        border-radius: 8px;\n        padding: 3px 7px;\n        color: #94a3b8;\n        font-size: 10px;\n        white-space: nowrap;\n      }\n\n      .claire-dashboard-search-results {\n        display: none;\n        margin-top: 8px;\n        border: 1px solid rgba(0, 212, 255, 0.22);\n        border-radius: 18px;\n        background: rgba(3, 8, 18, 0.96);\n        backdrop-filter: blur(18px);\n        box-shadow: 0 22px 52px rgba(0, 0, 0, 0.34);\n        max-height: min(72vh, 620px);\n        overflow: auto;\n        padding: 8px;\n      }\n\n      .claire-dashboard-search-results.open {\n        display: block;\n      }\n\n      .claire-dashboard-search-result {\n        display: block;\n        width: 100%;\n        text-align: left;\n        border: 1px solid rgba(148, 163, 184, 0.12);\n        border-radius: 14px;\n        padding: 10px 12px;\n        margin: 6px 0;\n        background: rgba(15, 23, 42, 0.52);\n        color: #e2e8f0;\n        cursor: pointer;\n      }\n\n      .claire-dashboard-search-result:hover,\n      .claire-dashboard-search-result.active {\n        border-color: rgba(0, 212, 255, 0.45);\n        background: rgba(0, 212, 255, 0.08);\n      }\n\n      .claire-dashboard-search-result-title {\n        color: #f8fafc;\n        font-weight: 800;\n        font-size: 12px;\n        line-height: 1.4;\n        overflow-wrap: anywhere;\n      }\n\n      .claire-dashboard-search-result-meta {\n        margin-top: 2px;\n        color: #7dd3fc;\n        font-size: 10px;\n        letter-spacing: .06em;\n        text-transform: uppercase;\n        overflow-wrap: anywhere;\n      }\n\n      .claire-dashboard-search-result-snippet {\n        margin-top: 6px;\n        color: #94a3b8;\n        font-size: 12px;\n        line-height: 1.5;\n        overflow-wrap: anywhere;\n      }\n\n      .claire-dashboard-search-empty {\n        padding: 12px;\n        color: #94a3b8;\n        font-size: 12px;\n        line-height: 1.5;\n      }\n\n      .claire-search-highlight {\n        outline: 2px solid rgba(0, 212, 255, 0.75) !important;\n        box-shadow: 0 0 24px rgba(0, 212, 255, 0.22) !important;\n      }\n\n      @media (max-width: 720px) {\n        .claire-dashboard-search-label {\n          display: none;\n        }\n\n        .claire-dashboard-search-kbd {\n          display: none;\n        }\n\n        .claire-dashboard-search-input {\n          font-size: 13px;\n        }\n      }\n    `;\n    document.head.appendChild(style);\n  }\n\n  function renderShell() {\n    if (document.getElementById("claire-dashboard-search-shell")) return;\n\n    ensureStyles();\n\n    const shell = document.createElement("div");\n    shell.id = "claire-dashboard-search-shell";\n    shell.className = "claire-dashboard-search-shell";\n    shell.innerHTML = `\n      <div class="claire-dashboard-search-box">\n        <div class="claire-dashboard-search-label">Claire Search</div>\n        <input\n          id="claire-dashboard-search-input"\n          class="claire-dashboard-search-input"\n          autocomplete="off"\n          spellcheck="false"\n          placeholder="Search runtime truth, routes, stages, validation, memory, architecture…"\n          aria-label="Claire dashboard search"\n        />\n        <div class="claire-dashboard-search-kbd">Ctrl K</div>\n      </div>\n      <div id="claire-dashboard-search-results" class="claire-dashboard-search-results" role="listbox"></div>\n    `;\n    document.body.appendChild(shell);\n    document.body.classList.add("claire-search-mounted");\n\n    const input = document.getElementById("claire-dashboard-search-input");\n    const results = document.getElementById("claire-dashboard-search-results");\n\n    input.addEventListener("input", () => {\n      state.lastQuery = input.value;\n      state.selectedIndex = -1;\n      renderResults(search(input.value));\n    });\n\n    input.addEventListener("focus", () => {\n      if (input.value.trim()) {\n        renderResults(search(input.value));\n      } else {\n        renderResults([]);\n      }\n      results.classList.add("open");\n    });\n\n    input.addEventListener("keydown", (event) => {\n      const buttons = Array.from(results.querySelectorAll(".claire-dashboard-search-result"));\n      if (event.key === "Escape") {\n        results.classList.remove("open");\n        input.blur();\n      } else if (event.key === "ArrowDown") {\n        event.preventDefault();\n        state.selectedIndex = Math.min(buttons.length - 1, state.selectedIndex + 1);\n        markActive(buttons);\n      } else if (event.key === "ArrowUp") {\n        event.preventDefault();\n        state.selectedIndex = Math.max(0, state.selectedIndex - 1);\n        markActive(buttons);\n      } else if (event.key === "Enter" && state.selectedIndex >= 0 && buttons[state.selectedIndex]) {\n        event.preventDefault();\n        buttons[state.selectedIndex].click();\n      }\n    });\n\n    document.addEventListener("keydown", (event) => {\n      const isMac = navigator.platform.toUpperCase().includes("MAC");\n      if ((isMac ? event.metaKey : event.ctrlKey) && event.key.toLowerCase() === "k") {\n        event.preventDefault();\n        input.focus();\n        input.select();\n        results.classList.add("open");\n      }\n    });\n\n    document.addEventListener("click", (event) => {\n      if (!shell.contains(event.target)) {\n        results.classList.remove("open");\n      }\n    });\n  }\n\n  function markActive(buttons) {\n    buttons.forEach((button, index) => {\n      button.classList.toggle("active", index === state.selectedIndex);\n      if (index === state.selectedIndex) {\n        button.scrollIntoView({ block: "nearest" });\n      }\n    });\n  }\n\n  function renderResults(items) {\n    const results = document.getElementById("claire-dashboard-search-results");\n    if (!results) return;\n\n    results.classList.add("open");\n\n    if (!state.lastQuery.trim()) {\n      results.innerHTML = `\n        <div class="claire-dashboard-search-empty">\n          Search local Claire dashboard truth. Current v17.62 mode does not fake internet or autonomous intelligence results.\n        </div>\n      `;\n      return;\n    }\n\n    if (!items.length) {\n      results.innerHTML = `\n        <div class="claire-dashboard-search-empty">\n          No local dashboard/runtime matches found for <strong>${escapeHtml(state.lastQuery)}</strong>.\n          If this should exist, generate runtime truth, validation, and memory reports first.\n        </div>\n      `;\n      return;\n    }\n\n    results.innerHTML = items.map((item, index) => `\n      <button class="claire-dashboard-search-result" data-index="${index}" type="button">\n        <div class="claire-dashboard-search-result-title">${escapeHtml(item.doc.title)}</div>\n        <div class="claire-dashboard-search-result-meta">${escapeHtml(item.doc.type)} · ${escapeHtml(item.doc.path)}</div>\n        <div class="claire-dashboard-search-result-snippet">${escapeHtml(item.snippet)}</div>\n      </button>\n    `).join("");\n\n    Array.from(results.querySelectorAll(".claire-dashboard-search-result")).forEach((button, index) => {\n      button.addEventListener("click", () => openResult(items[index].doc));\n    });\n  }\n\n  function openResult(doc) {\n    const results = document.getElementById("claire-dashboard-search-results");\n    if (results) results.classList.remove("open");\n\n    if (doc.targetId) {\n      const node = document.getElementById(doc.targetId);\n      if (node) {\n        document.querySelectorAll(".claire-search-highlight").forEach((el) => el.classList.remove("claire-search-highlight"));\n        node.classList.add("claire-search-highlight");\n        node.scrollIntoView({ behavior: "smooth", block: "start" });\n        window.setTimeout(() => node.classList.remove("claire-search-highlight"), 2600);\n      }\n      return;\n    }\n\n    const panel = ensureJsonResultPanel();\n    panel.innerHTML = `\n      <div class="claire-dashboard-search-result-title">Local truth file: ${escapeHtml(doc.title)}</div>\n      <div class="claire-dashboard-search-result-meta">${escapeHtml(doc.path)}</div>\n      <pre style="margin-top:10px; white-space:pre-wrap; overflow-wrap:anywhere; max-height:52vh; overflow:auto;">${escapeHtml(JSON.stringify(doc.json ?? doc.text, null, 2))}</pre>\n    `;\n    panel.scrollIntoView({ behavior: "smooth", block: "start" });\n  }\n\n  function ensureJsonResultPanel() {\n    let panel = document.getElementById("claire-search-json-result-panel");\n    if (!panel) {\n      panel = document.createElement("section");\n      panel.id = "claire-search-json-result-panel";\n      panel.className = "claire-dashboard-search-results open";\n      panel.style.display = "block";\n      panel.style.position = "relative";\n      panel.style.margin = "18px auto";\n      panel.style.width = "min(100%, 1180px)";\n      panel.style.transform = "none";\n      const mount = document.querySelector("main") || document.getElementById("app") || document.body;\n      mount.appendChild(panel);\n    }\n    return panel;\n  }\n\n  async function boot() {\n    renderShell();\n\n    // Delay visible text indexing slightly so prior dashboard bridge panels can mount.\n    window.setTimeout(async () => {\n      state.documents = [];\n      collectVisibleSections();\n      await collectJsonDocuments();\n      const input = document.getElementById("claire-dashboard-search-input");\n      if (input?.value?.trim()) {\n        renderResults(search(input.value));\n      }\n    }, 500);\n  }\n\n  if (document.readyState === "loading") {\n    document.addEventListener("DOMContentLoaded", boot);\n  } else {\n    boot();\n  }\n})();\n', 'src/claire/dashboard_intelligence/__init__.py': '"""\nClaire v17.62 Dashboard Intelligence Foundation.\n\nThis package creates a local search/intelligence index for dashboard-facing\ntruth files. It is intentionally local and honest: no fake internet search,\nno fake standalone intelligence, and no memory mutation.\n"""\n\nfrom .local_index import build_dashboard_intelligence_index\n\n__all__ = ["build_dashboard_intelligence_index"]\n', 'src/claire/dashboard_intelligence/local_index.py': 'from __future__ import annotations\n\nimport json\nfrom datetime import datetime, timezone\nfrom pathlib import Path\nfrom typing import Any, Dict, Iterable, List\n\n\nDEFAULT_RELATIVE_PATHS = [\n    "src/frontend/command_center/modern/dashboard_architecture_map.json",\n    "src/frontend/command_center/modern/lifecycle_stage_registry.json",\n    "src/frontend/command_center/modern/runtime_surface_registry.json",\n    "src/frontend/command_center/modern/route_surface_registry.json",\n    "src/frontend/command_center/modern/runtime_truth_contract.json",\n    "src/frontend/command_center/modern/runtime_truth_status.json",\n    "src/frontend/command_center/modern/validation_authority_status.json",\n    "src/frontend/command_center/modern/evidence_traceability_status.json",\n    "src/frontend/command_center/modern/verified_memory_status.json",\n    "src/frontend/command_center/modern/recursive_feedback_status.json",\n    "exports/latest/dashboard_runtime_truth.json",\n    "exports/latest/validation_authority_report.json",\n    "exports/latest/evidence_traceability_index.json",\n    "exports/latest/verified_memory_gate_report.json",\n    "exports/latest/recursive_feedback_gate_report.json",\n]\n\n\ndef utc_now() -> str:\n    return datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")\n\n\ndef flatten_json(value: Any, prefix: str = "") -> List[str]:\n    rows: List[str] = []\n\n    def walk(node: Any, path: str) -> None:\n        if node is None:\n            return\n        if isinstance(node, dict):\n            for key, item in node.items():\n                next_path = f"{path}.{key}" if path else str(key)\n                walk(item, next_path)\n            return\n        if isinstance(node, list):\n            for index, item in enumerate(node):\n                walk(item, f"{path}[{index}]")\n            return\n        rows.append(f"{path}: {node}")\n\n    walk(value, prefix)\n    return rows\n\n\ndef read_json(path: Path) -> Dict[str, Any] | None:\n    if not path.exists() or not path.is_file():\n        return None\n    try:\n        with path.open("r", encoding="utf-8") as handle:\n            value = json.load(handle)\n        return value if isinstance(value, dict) else {"value": value}\n    except Exception:\n        return None\n\n\ndef build_dashboard_intelligence_index(project_root: Path, relative_paths: Iterable[str] = DEFAULT_RELATIVE_PATHS) -> Dict[str, Any]:\n    documents: List[Dict[str, Any]] = []\n\n    for relative in relative_paths:\n        path = project_root / relative\n        data = read_json(path)\n        if data is None:\n            documents.append({\n                "path": relative,\n                "status": "missing",\n                "title": Path(relative).name,\n                "text": "",\n                "terms": [],\n            })\n            continue\n\n        rows = flatten_json(data)\n        text = "\\n".join(rows)\n        terms = sorted({\n            token.strip(".,:;()[]{}<>\\"\'").lower()\n            for token in text.replace("\\n", " ").split(" ")\n            if len(token.strip(".,:;()[]{}<>\\"\'")) >= 3\n        })\n\n        documents.append({\n            "path": relative,\n            "status": "indexed",\n            "title": Path(relative).name,\n            "text": text[:50000],\n            "term_count": len(terms),\n            "terms": terms[:2000],\n        })\n\n    indexed = [doc for doc in documents if doc["status"] == "indexed"]\n\n    return {\n        "schema": "claire.dashboard_intelligence_index.v1",\n        "version": "17.62",\n        "generated_at": utc_now(),\n        "mode": "local_dashboard_truth_search",\n        "standalone_intelligence_ready": False,\n        "standalone_note": "This is the local index foundation for a future standalone Claire intelligence engine.",\n        "documents_total": len(documents),\n        "documents_indexed": len(indexed),\n        "documents_missing": len(documents) - len(indexed),\n        "documents": documents,\n    }\n', 'tools/claire_build_dashboard_search_index.py': 'from __future__ import annotations\n\nimport argparse\nimport json\nimport sys\nfrom pathlib import Path\n\n\ndef _bootstrap(project_root: Path) -> None:\n    for candidate in (project_root, project_root / "src"):\n        candidate_str = str(candidate)\n        if candidate.exists() and candidate_str not in sys.path:\n            sys.path.insert(0, candidate_str)\n\n\ndef main() -> int:\n    parser = argparse.ArgumentParser(description="Build Claire v17.62 local dashboard intelligence/search index.")\n    parser.add_argument("--project-root", default=".", help="Claire project root. Defaults to current directory.")\n    parser.add_argument("--out", default=None, help="Optional output path.")\n    args = parser.parse_args()\n\n    project_root = Path(args.project_root).resolve()\n    _bootstrap(project_root)\n\n    try:\n        from claire.dashboard_intelligence.local_index import build_dashboard_intelligence_index\n    except Exception as exc:\n        print(f"[Claire v17.62] Import error: {exc}", file=sys.stderr)\n        return 2\n\n    index = build_dashboard_intelligence_index(project_root)\n    out_path = Path(args.out).resolve() if args.out else project_root / "src" / "frontend" / "command_center" / "modern" / "dashboard_search_index.json"\n    out_path.parent.mkdir(parents=True, exist_ok=True)\n    out_path.write_text(json.dumps(index, indent=2, ensure_ascii=False) + "\\n", encoding="utf-8")\n\n    latest = project_root / "exports" / "latest" / "dashboard_search_index.json"\n    latest.parent.mkdir(parents=True, exist_ok=True)\n    latest.write_text(json.dumps(index, indent=2, ensure_ascii=False) + "\\n", encoding="utf-8")\n\n    print("[Claire v17.62] Dashboard search/intelligence index written:")\n    print(f"  {out_path}")\n    print(f"  {latest}")\n    print(f"[Claire v17.62] Indexed {index.get(\'documents_indexed\')} of {index.get(\'documents_total\')} known local truth files.")\n    return 0\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n', 'src/frontend/command_center/modern/dashboard_search_index.json': '{\n  "schema": "claire.dashboard_intelligence_index.v1",\n  "version": "17.62",\n  "mode": "local_dashboard_truth_search",\n  "standalone_intelligence_ready": false,\n  "documents_total": 0,\n  "documents_indexed": 0,\n  "message": "Run tools/claire_build_dashboard_search_index.py after reports are generated to build the local search index."\n}\n', 'docs/dashboard/v17.62_portal_resize_search.md': '# Claire v17.62 — Portal Resize + Dashboard Search Foundation\n\n## Purpose\n\nv17.62 fixes two immediate operating-environment issues:\n\n1. Portal panels need to be resized and made readable so content is viewable.\n2. The dashboard needs an integrated search/intelligence command bar.\n\nThis build is also a foundation for Claire becoming a standalone intelligence, but it does not fake that capability. Current mode is local dashboard/runtime truth search.\n\n## Installed dashboard files\n\n```text\nsrc/frontend/command_center/modern/claire_portal_responsive_layout.css\nsrc/frontend/command_center/modern/claire_dashboard_search.js\nsrc/frontend/command_center/modern/dashboard_search_contract.json\nsrc/frontend/command_center/modern/intelligence_command_contract.json\nsrc/frontend/command_center/modern/dashboard_search_index.json\n```\n\n## Installed system files\n\n```text\nsrc/claire/dashboard_intelligence/__init__.py\nsrc/claire/dashboard_intelligence/local_index.py\ntools/claire_build_dashboard_search_index.py\n```\n\n## Search behavior\n\nThe search bar indexes:\n\n- visible dashboard surfaces\n- architecture registries\n- lifecycle and route registries\n- runtime truth status\n- validation authority reports\n- evidence traceability reports\n- verified memory reports\n- recursive feedback reports\n\n## Command\n\nAfter run/validation/memory reports exist:\n\n```bash\npython tools/claire_build_dashboard_search_index.py\n```\n\n## Important limitation\n\nv17.62 does not claim full standalone intelligence. It creates the dashboard command/search foundation that a future standalone Claire intelligence service can use.\n', 'docs/update_packs/v17.62_dashboard_update_pack.md': '# v17.62 Dashboard Update Pack\n\n## Architecture section covered\n\n- Operating Environment usability\n- Runtime Infrastructure visibility\n- Lifecycle Contracts visibility\n- Output/Validation/Memory searchability\n- Future standalone intelligence command layer\n\n## Dashboard changes\n\nInstalled:\n\n```text\nsrc/frontend/command_center/modern/claire_portal_responsive_layout.css\nsrc/frontend/command_center/modern/claire_dashboard_search.js\nsrc/frontend/command_center/modern/dashboard_search_contract.json\nsrc/frontend/command_center/modern/intelligence_command_contract.json\nsrc/frontend/command_center/modern/dashboard_search_index.json\n```\n\nPatched:\n\n```text\nsrc/frontend/command_center/modern/index.html\n```\n\n## User-facing changes\n\n- Dashboard panels/portals are more readable.\n- Portals can scroll instead of hiding content.\n- Many portal cards are vertically resizable.\n- Search bar appears at the top of the dashboard.\n- Ctrl+K focuses Claire Search.\n- Search results can jump to visible dashboard panels or inspect local truth JSON.\n', 'docs/update_packs/v17.62_system_runtime_update_pack.md': '# v17.62 System Runtime Update Pack\n\n## Runtime purpose\n\nAdd a local dashboard intelligence index foundation for future standalone Claire intelligence.\n\n## Installed files\n\n```text\nsrc/claire/dashboard_intelligence/__init__.py\nsrc/claire/dashboard_intelligence/local_index.py\ntools/claire_build_dashboard_search_index.py\n```\n\n## Command\n\n```bash\npython tools/claire_build_dashboard_search_index.py\n```\n\n## Scope\n\nCurrent search mode is local dashboard/runtime truth search.\n\nIt does not provide:\n\n- fake autonomous internet search\n- fake standalone intelligence\n- self-mutating runtime\n- unvalidated memory writes\n\nFuture standalone intelligence should connect to this layer through the dashboard search and intelligence command contracts.\n', 'data/build_manifests/v17.62_portal_resize_search_manifest.json': '{\n  "version": "17.62",\n  "name": "Portal Resize + Dashboard Search Foundation",\n  "build_type": "dashboard_stabilization_and_intelligence_foundation",\n  "purpose": "Resize/readability repair for all portals and add dashboard-wide local truth search foundation.",\n  "depends_on": [\n    "v17.56 Operating Environment Redesign Foundation",\n    "v17.59 Runtime Truth Backbone",\n    "v17.60 Validation Authority",\n    "v17.61 Verified Memory Gate"\n  ],\n  "installed_files": [\n    "docs/dashboard/v17.62_portal_resize_search.md",\n    "docs/update_packs/v17.62_dashboard_update_pack.md",\n    "docs/update_packs/v17.62_system_runtime_update_pack.md",\n    "src/claire/dashboard_intelligence/__init__.py",\n    "src/claire/dashboard_intelligence/local_index.py",\n    "src/frontend/command_center/modern/claire_dashboard_search.js",\n    "src/frontend/command_center/modern/claire_portal_responsive_layout.css",\n    "src/frontend/command_center/modern/dashboard_search_contract.json",\n    "src/frontend/command_center/modern/dashboard_search_index.json",\n    "src/frontend/command_center/modern/intelligence_command_contract.json",\n    "tools/claire_build_dashboard_search_index.py"\n  ],\n  "post_install_commands": [\n    "python tools/claire_build_runtime_truth.py",\n    "python tools/claire_validate_runtime_truth.py",\n    "python tools/claire_build_verified_memory.py",\n    "python tools/claire_build_dashboard_search_index.py"\n  ],\n  "safety": {\n    "rollback_backups": true,\n    "launcher_path_preserved": "src/frontend/command_center/modern/index.html",\n    "no_fake_search_results": true,\n    "no_fake_standalone_intelligence": true,\n    "runtime_logic_unchanged": true\n  }\n}\n'}

CSS_FILE = "claire_portal_responsive_layout.css"
SEARCH_SCRIPT = "claire_dashboard_search.js"

def utc_stamp() -> str:
    return datetime.utcnow().strftime("%Y%m%d_%H%M%S")

def project_root() -> Path:
    return Path.cwd().resolve()

def backup_existing(root: Path, relative_path: str, backup_root: Path) -> None:
    target = root / relative_path
    if not target.exists():
        return
    backup_path = backup_root / relative_path
    backup_path.parent.mkdir(parents=True, exist_ok=True)
    if target.is_file():
        shutil.copy2(target, backup_path)
    elif target.is_dir():
        if backup_path.exists():
            shutil.rmtree(backup_path)
        shutil.copytree(target, backup_path)

def write_text(root: Path, relative_path: str, content: str, backup_root: Path) -> None:
    target = root / relative_path
    backup_existing(root, relative_path, backup_root)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8")

def patch_index_html(root: Path, backup_root: Path) -> bool:
    index_rel = "src/frontend/command_center/modern/index.html"
    index_path = root / index_rel
    if not index_path.exists():
        return False

    html = index_path.read_text(encoding="utf-8", errors="ignore")
    original = html

    if CSS_FILE not in html:
        css_tag = '\n<link rel="stylesheet" href="claire_portal_responsive_layout.css">\n'
        if "</head>" in html:
            html = html.replace("</head>", css_tag + "</head>", 1)
        else:
            html = css_tag + html

    if SEARCH_SCRIPT not in html:
        script_tag = '\n<script src="claire_dashboard_search.js"></script>\n'
        if "</body>" in html:
            html = html.replace("</body>", script_tag + "</body>", 1)
        else:
            html = html + script_tag

    if html != original:
        backup_existing(root, index_rel, backup_root)
        index_path.write_text(html, encoding="utf-8")

    return True

def write_install_record(root: Path, backup_root: Path, index_patched: bool) -> None:
    record = {
        "version": VERSION,
        "build_name": BUILD_NAME,
        "installed_at_utc": datetime.utcnow().isoformat() + "Z",
        "project_root": str(root),
        "backup_root": str(backup_root),
        "index_patched": index_patched,
        "files_written": sorted(FILES.keys()),
        "post_install_commands": [
            "python tools/claire_build_runtime_truth.py",
            "python tools/claire_validate_runtime_truth.py",
            "python tools/claire_build_verified_memory.py",
            "python tools/claire_build_dashboard_search_index.py"
        ]
    }
    record_path = root / "data" / "build_manifests" / "v17.62_install_record.json"
    record_path.parent.mkdir(parents=True, exist_ok=True)
    record_path.write_text(json.dumps(record, indent=2) + "\n", encoding="utf-8")

def main() -> None:
    root = project_root()
    backup_root = root / "backups" / f"claire_v17_62_{utc_stamp()}"
    backup_root.mkdir(parents=True, exist_ok=True)

    for relative_path, content in FILES.items():
        write_text(root, relative_path, content, backup_root)

    index_patched = patch_index_html(root, backup_root)
    write_install_record(root, backup_root, index_patched)

    print("=" * 72)
    print(f"Claire v{VERSION} installed: {BUILD_NAME}")
    print("=" * 72)
    print(f"Project root: {root}")
    print(f"Backups:      {backup_root}")
    print("")
    print("Installed portal resizing/readability CSS, dashboard search bar,")
    print("local dashboard intelligence index tooling, contracts, docs, and manifest.")
    print("")
    print("After run/validation/memory reports exist, run:")
    print("  python tools/claire_build_dashboard_search_index.py")
    print("")
    print("Search shortcut in dashboard:")
    print("  Ctrl+K")
    print("")
    if index_patched:
        print("Dashboard patched:")
        print("  src/frontend/command_center/modern/index.html")
    else:
        print("Note: index.html was not found. Files were installed but automatic")
        print("dashboard CSS/script injection could not be completed.")
    print("=" * 72)

if __name__ == "__main__":
    main()
